struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* reverseList(ListNode* head)
{
    vector<int> values;
    for (ListNode* n = head; n; n = n->next) values.push_back(n->val);

    ListNode* n = head;
    for (int i = values.size() - 1; i >= 0; i--)
    {
        n->val = values[i];
        n = n->next;
    }

    return head;
}

