    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* middleNode(ListNode* head)
{
    int length = 0;
    for (ListNode* n = head; n; n = n->next) length++;

    ListNode* current = head;
    for (int i = 0; i < length / 2; i++) current = current->next;

    return current;
}

